--
-- Bẫy `appointments`
--
DELIMITER $$
CREATE TRIGGER `check_staff_role_insert` BEFORE INSERT ON `appointments` FOR EACH ROW BEGIN
    IF NEW.staff_id IS NOT NULL THEN
        IF NOT EXISTS (SELECT 1 FROM user_roles WHERE user_id = NEW.staff_id AND role_id = 2) THEN
            SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Error: The assigned user does not have STAFF role.';
        END IF;
    END IF;
END
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `check_staff_role_update` BEFORE UPDATE ON `appointments` FOR EACH ROW BEGIN
    IF NEW.staff_id IS NOT NULL AND (OLD.staff_id IS NULL OR NEW.staff_id != OLD.staff_id) THEN
        IF NOT EXISTS (SELECT 1 FROM user_roles WHERE user_id = NEW.staff_id AND role_id = 2) THEN
            SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Error: The assigned user does not have STAFF role.';
        END IF;
    END IF;
END
$$
DELIMITER ;

