--
-- Bẫy `product_reviews`
--
DELIMITER $$
CREATE TRIGGER `update_rating_after_delete` AFTER DELETE ON `product_reviews` FOR EACH ROW BEGIN
    IF OLD.parent_id IS NULL THEN
        UPDATE products p
        SET 
            p.average_rating = (
                SELECT IFNULL(AVG(rating), 0) 
                FROM product_reviews 
                WHERE product_id = OLD.product_id AND parent_id IS NULL
            ),
            p.review_count = (
                SELECT COUNT(*) 
                FROM product_reviews 
                WHERE product_id = OLD.product_id AND parent_id IS NULL
            )
        WHERE p.id = OLD.product_id;
    END IF;
END
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `update_rating_after_insert` AFTER INSERT ON `product_reviews` FOR EACH ROW BEGIN
    -- Chỉ tính toán nếu đây là đánh giá gốc (không phải là comment trả lời)
    IF NEW.parent_id IS NULL THEN
        UPDATE products p
        SET 
            p.average_rating = (
                SELECT IFNULL(AVG(rating), 0) 
                FROM product_reviews 
                WHERE product_id = NEW.product_id AND parent_id IS NULL
            ),
            p.review_count = (
                SELECT COUNT(*) 
                FROM product_reviews 
                WHERE product_id = NEW.product_id AND parent_id IS NULL
            )
        WHERE p.id = NEW.product_id;
    END IF;
END
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `update_rating_after_update` AFTER UPDATE ON `product_reviews` FOR EACH ROW BEGIN
    IF NEW.parent_id IS NULL THEN
        UPDATE products p
        SET 
            p.average_rating = (
                SELECT IFNULL(AVG(rating), 0) 
                FROM product_reviews 
                WHERE product_id = NEW.product_id AND parent_id IS NULL
            ),
            p.review_count = (
                SELECT COUNT(*) 
                FROM product_reviews 
                WHERE product_id = NEW.product_id AND parent_id IS NULL
            )
        WHERE p.id = NEW.product_id;
    END IF;
END
$$
DELIMITER ;

